// Parsea la salida JSON del content engine y crea 1 item por plataforma.
const raw = $input.first().json.stdout || '{}';
const data = JSON.parse(raw);

const emojis = { linkedin: '💼', twitter: '🐦', instagram: '📸', tiktok: '🎬', threads: '🧵' };

return Object.entries(data.posts).map(([platform, content]) => ({
  json: {
    platform,
    emoji: emojis[platform] || '📤',
    content,
    chars: content.length,
    insight: data.insight_title,
    timestamp: data.timestamp
  }
}));
